import{_ as n,o as a,c as o,j as e}from"./chunks/framework.DsiwUQoa.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Note/这分明不是我的错/index.md","filePath":"Note/这分明不是我的错/index.md"}'),l={name:"Note/这分明不是我的错/index.md"};function r(s,t,i,d,c,p){return a(),o("div",null,[...t[0]||(t[0]=[e("ul",null,[e("li",null,"事情发生时：26年5月26日"),e("li",null,"该文章编写日期：26年6月8日")],-1),e("p",null,"我跟我的同桌玩（A)，但 B 走了过来问 A 是在和我玩吗，A 回答不是，B 已经连续几天这样了，这让我很生气，我就跟他在走廊上理论，结果我跟他说了那么多他根本没听，还把肩抬起来一下然后和他的朋友说“走，我们去玩，不要理这个疯子”我那时就很生气，我就想要把他拉回来继续理论可他却打了我，我打不过他，我就很崩溃，我就在那吼他，然后没过一会就上课了，同学们就把这件事告诉了老师，老师就把我叫上讲台，老师没有处理这件事，他直接对我进行了长达30分钟的人身攻击，一节课也才40分钟，然后把A的座位调走了，我就没有同桌了，老师还明知故问的问有人愿意和我座吗，A想举手，但老师用眼神警示他，然后老师看到没人举手后，又明知故问的问，有人愿意和我玩吗，我的其他朋友没有举手，因为他们不敢，然后老师就说了一堆杂七杂八的，我不想在复述一边，后面我被叫回座位了，我就趴在桌子上假装是在睡觉，实际上是在哭 后来我了解到，A是在和我玩，而且玩的很开心，而B问他时他回答不是是因为如果回答是，B会在背后说他的坏话，以及传播出去，而B这样是想让A和他玩，也就是说，在这件事里我没有任何错误",-1)])])}const _=n(l,[["render",r]]);export{m as __pageData,_ as default};
